@module scratch  src=scratch.lua  loc=72  sha=ca82072  mode=namespace  self=scratch

# Invariants & contracts
  @invariant  identity is the projext guid (continuum_wiring/scratch), not module state — instances interchangeable  @ 4
  @invariant  the track is always hidden + muted; re-located by guid each call (REAPER handles go stale)  @ 5
  @contract  id()/track() mint on first use; peek() never mints  @ 6

# Module-level constants
  @const PROJ = 0  @ 8
  @const EXT_SECTION = 'continuum_wiring'  @ 9
  @const GUID_KEY = 'scratch'  @ 10
  @const scratch = {}  @ 12

# Private functions
  -- mint + locate
  @fn locate(guid)  @ 17-22
      -- By guid over project tracks (the scratch is never master).
  @fn mint()  @ 27-47
      -- Append top-level: if the project ends inside an open folder, an appended
      -- track joins it and retargets its mainSend to the parent. Copied from
      -- rm:addTrack (not called) to keep this module dependency-free; see docs.

# Public API (scratch.*)
  @api scratch.peek()  @ 52-57
      @contract  persisted guid + live handle, or nil if none minted yet. Never mints.  @ 51
  @api scratch.id()  @ 60-63
      @contract  the scratch track's guid, minted (hidden + muted) on first use; persisted in projext.  @ 59
  @api scratch.track()  @ 66-70
      @contract  the scratch track handle; mints on first use.  @ 65

# REAPER API surface
  @reaper CountTracks
  @reaper GetTrack
  @reaper GetTrackGUID
  @reaper GetMediaTrackInfo_Value
  @reaper SetMediaTrackInfo_Value
  @reaper InsertTrackAtIndex
  @reaper GetSetMediaTrackInfo_String
  @reaper SetProjExtState
  @reaper GetProjExtState

# Fields (r read / w write incl. constructor keys)
  @field w id  @ id:60
  @field w peek  @ peek:52
  @field w track  @ track:66
